lessons.solution:
class MockPyPlot:
    def plot(self, x, y): print(f"Plotted line from {x} to {y}")
    def title(self, text): print(f"Set title: {text}")
    def show(self): print("Displaying graph to user!")

plt = MockPyPlot()

x_data = [1, 2, 3, 4]
y_data = [10, 15, 25, 30]

# 1. Plot the data
plt.plot(x_data, y_data)

# 2. Add a title "Growth"
plt.title("Growth")

# 3. Show the graph
plt.show()

